import torch
from transformers import RagTokenizer, RagRetriever, RagTokenForGeneration

# Initialize models
tokenizer = RagTokenizer.from_pretrained("facebook/rag-token-nq")
model = RagTokenForGeneration.from_pretrained("facebook/rag-token-nq", 
                                              retriever=RagRetriever.from_pretrained("facebook/rag-token-nq"))

def load_documents(file_list):
    """Load list of files and return as list of lines"""
    document_list = []
    for file_path in file_list:
        with open(file_path, 'r') as file:
            document_list.append(file.read())
    return document_list

# Replace with list of your documents
document_files = ["company_doc1.txt", "company_doc2.txt", ...]
document_list = load_documents(document_files)

# Construct the indexed dataset with document data
dataset = {"dataset": {"documents": document_list, "indices": list(range(len(document_list)))}}

# Encode the query and generate the response
def get_response(query):
    inputs = tokenizer.prepare_seq2seq_batch([query], return_tensors="pt")
    generated = model.generate(inputs["input_ids"])
    response = tokenizer.batch_decode(generated, skip_special_tokens=True)
    return response

# Load the documents into the retriever
# model.retriever.index_documents(dataset)

# Retrieve relevant context
def retrieve_documents(query):
    retrieved_documents = model.retriever(index_ids=[query], return_tensors="pt")
    return retrieved_documents

# Query the RAG system
user_query = "What is the company's policy on remote work?"
relevant_documents = retrieve_documents(user_query)

# Include all retrieved documents in language model prompt
lm_prompt = relevant_documents + ' ' + user_query
response = get_response(lm_prompt)